parameters.query:
SELECT * FROM ofertas_infojobs 
WHERE created_at >= NOW() - INTERVAL '24 HOURS' 
ORDER BY match_score DESC;

parameters.jsCode:
const items = $input.all();

// Si un día el mercado está parado y no hay nada nuevo, salimos elegantemente
if (items.length === 0) {
    return [{ json: { cuerpo_email: "<div style='font-family: Arial; color: #555;'><p>Hoy no se han detectado ofertas nuevas en las últimas 24 horas.</p></div>" } }];
}

// Inicializamos los contenedores de texto para cada categoría
let prioridadAlta = "";
let prioridadMedia = "";
let prioridadBaja = "";

// Iteramos sobre el array de ofertas para maquetar y clasificar
for (const item of items) {
  let oferta = item.json;

  // Plantilla HTML limpia para cada tarjeta de oferta
  let tarjetaOferta = `
    <div style="margin-bottom: 15px; padding: 15px; border-left: 4px solid #3498db; background-color: #f8f9fa; border-radius: 4px; font-family: Arial, sans-serif;">
      <span style="font-size: 14px; color: #7f8c8d; font-weight: bold; float: right;">Match: ${oferta.match_score}%</span>
      <b style="font-size: 16px; color: #2c3e50; display: block; max-width: 80%;">${oferta.titulo}</b>
      <span style="font-size: 14px; color: #34495e; display: block; margin-top: 3px;">🏢 ${oferta.empresa}</span>
      <p style="margin: 8px 0; font-size: 14px; color: #555; line-height: 1.4;">💡 <i>${oferta.motivo}</i></p>
      <a href="${oferta.enlace}" target="_blank" style="color: #3498db; text-decoration: none; font-weight: bold; font-size: 14px;">Postularse ahora →</a>
    </div>
  `;

  // Clasificamos la tarjeta en su sección correspondiente según la nota de la IA
  if (oferta.match_score >= 80) {
    prioridadAlta += tarjetaOferta;
  } else if (oferta.match_score >= 50) {
    prioridadMedia += tarjetaOferta;
  } else {
    prioridadBaja += tarjetaOferta;
  }
}

// Construimos el esqueleto del correo ensamblando las categorías existentes
let htmlFinal = "<div style='font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 10px;'>";
htmlFinal += "<h2 style='color: #2c3e50; border-bottom: 2px solid #ecf0f1; padding-bottom: 10px; margin-bottom: 20px;'>📋 Reporte de Captación de Talento</h2>";

if (prioridadAlta) {
  htmlFinal += "<h3 style='color: #e74c3c; margin-top: 30px; border-bottom: 1px dashed #e74c3c; padding-bottom: 5px;'>🔥 Imprescindibles (Match ≥ 80%)</h3>" + prioridadAlta;
}

if (prioridadMedia) {
  htmlFinal += "<h3 style='color: #f39c12; margin-top: 30px; border-bottom: 1px dashed #f39c12; padding-bottom: 5px;'>📈 Posiciones de Interés (50% - 79%)</h3>" + prioridadMedia;
}

if (prioridadBaja) {
  htmlFinal += "<h3 style='color: #95a5a6; margin-top: 30px; border-bottom: 1px dashed #95a5a6; padding-bottom: 5px;'>⏳ Revisión Secundaria (< 50%)</h3>" + prioridadBaja;
}

htmlFinal += "</div>";

return [{ json: { cuerpo_email: htmlFinal } }];
